class Solution:
    def nextPermutation(self, nums: List[int]) -> None:
        """
        Do not return anything, modify nums in-place instead.
        """
        #find the breakpoint
        n = len(nums)
        ind= -1
        for i in range(n-2,-1,-1):
            if nums[i] < nums[i+1]:
                ind = i
                break

        if ind ==-1:
            nums.reverse()
            return nums

        #find the next greater element from right of the breakpoint to swap it with
        for i in range(n-1,-1,-1):
            if nums[i] > nums[ind]:
                nums[i] , nums[ind] = nums[ind] , nums[i]
                break

        #reverse the right half of the breakpoint
        nums[ind+1:] = reversed(nums[ind+1:])
        return nums

