class Solution:
    def searchRange(self, nums: List[int], target: int) -> List[int]:
        def findFirst():
            low, high = 0, len(nums) - 1
            first = -1
            while low <= high:
                mid = (low + high) // 2
                if nums[mid] == target:
                    first = mid
                    high = mid - 1  # continue searching left
                elif nums[mid] < target:
                    low = mid + 1
                else:
                    high = mid - 1
            return first

        def findLast():
            low, high = 0, len(nums) - 1
            last = -1
            while low <= high:
                mid = (low + high) // 2
                if nums[mid] == target:
                    last = mid
                    low = mid + 1  # continue searching right
                elif nums[mid] < target:
                    low = mid + 1
                else:
                    high = mid - 1
            return last

        first = findFirst()
        last = findLast()
        return [first, last] if first != -1 else [-1, -1]

