def printF(index,arr,s,k,count):
    if index == len(arr):
        if s == k:
            return 1
        else:
            return 0

    s+=arr[index]
    l = printF(index+1,arr,s,k,count)

    s-= arr[index]
    r = printF(index+1,arr,s,k,count)

